"""Reasoner protocol, shared prompt construction, and strict-output parsing.

The reasoner is consulted ONLY when memory evidence is thin or conflicting. It ranks
candidate models for a task; it never writes prompts, runs models, or does the task.
Its estimates are blended with the deterministic ones — it advises, it does not decide.
"""

from __future__ import annotations

import json
from collections.abc import Sequence
from dataclasses import dataclass
from typing import Any, Protocol, runtime_checkable

from minima.memory.records import clamp01
from minima.schemas.common import Difficulty, TaskType


@dataclass(slots=True)
class CandidateView:
    """The view of a candidate model handed to the reasoner."""

    model_id: str
    provider: str
    input_cost_per_mtok: float
    output_cost_per_mtok: float
    context_window: int
    capability_prior: float
    est_cost_usd: float
    predicted_success: float
    # Observed latency percentile (ms) from similar past outcomes; None without evidence.
    est_latency_ms: float | None = None


@dataclass(slots=True)
class ReasonerRanking:
    model_id: str
    predicted_success: float
    rationale: str


@dataclass(slots=True)
class ReasonerResult:
    rankings: list[ReasonerRanking]
    recommended: str | None = None
    fallback: str | None = None

    def by_model(self) -> dict[str, ReasonerRanking]:
        return {r.model_id: r for r in self.rankings}


@runtime_checkable
class Reasoner(Protocol):
    async def rank(
        self,
        *,
        task: str,
        task_type: str,
        difficulty: str,
        candidates: Sequence[CandidateView],
        memory_block: str,
        cost_quality_tradeoff: float,
    ) -> ReasonerResult | None: ...


# --- structured output schemas (additionalProperties:false everywhere for strict mode) ---

RANKING_SCHEMA: dict[str, Any] = {
    "type": "object",
    "properties": {
        "recommended": {"type": "string"},
        "fallback": {"type": ["string", "null"]},
        "ranking": {
            "type": "array",
            "items": {
                "type": "object",
                "properties": {
                    "model_id": {"type": "string"},
                    "predicted_success": {"type": "number"},
                    "rationale": {"type": "string"},
                },
                "required": ["model_id", "predicted_success", "rationale"],
                "additionalProperties": False,
            },
        },
    },
    "required": ["recommended", "fallback", "ranking"],
    "additionalProperties": False,
}

CLASSIFY_SCHEMA: dict[str, Any] = {
    "type": "object",
    "properties": {
        "task_type": {"type": "string", "enum": [t.value for t in TaskType]},
        "difficulty": {"type": "string", "enum": [d.value for d in Difficulty]},
    },
    "required": ["task_type", "difficulty"],
    "additionalProperties": False,
}

from __future__ import annotations

from pathlib import Path

from pydantic import BaseModel, Field

from minima_harness.agent.tools import AgentTool, ToolResult, error_result
from minima_harness.ai.types import TextContent
from minima_harness.tools._io import read_lines


class ReadParams(BaseModel):
    path: str
    offset: int = Field(default=1, ge=1)
    limit: int = Field(default=2000, ge=1)


async def _execute(tool_call_id: str, params, signal, on_update) -> ToolResult:  # noqa: ANN001
    assert isinstance(params, ReadParams)
    p = Path(params.path).expanduser()
    if not p.exists():
        return error_result(f"read: no such file: {p}")
    if p.is_dir():
        return error_result(f"read: is a directory: {p}")
    body, n = read_lines(p, offset=params.offset, limit=params.limit)
    return ToolResult(content=[TextContent(text=body or "(empty)")], details={"lines_read": n})


def read_tool() -> AgentTool:
    return AgentTool(
        name="read",
        description=(
            "Read a text file from the local filesystem. Returns lines with 1-based "
            "line numbers. Use `offset` and `limit` to page through large files."
        ),
        parameters=ReadParams,
        execute=_execute,
    )

from __future__ import annotations
from pydantic import BaseModel, Field
from minima_harness.agent.tools import AgentTool, ToolResult, ToolUpdate, error_result
from minima_harness.ai.types import TextContent
from minima_harness.tools._exa import exa_search

class WebSearchParams(BaseModel):
    query: str = Field(description="The search query.")
    num_results: int = Field(default=5, ge=1, le=10)

async def _execute(tool_call_id, params, signal, on_update: ToolUpdate | None) -> ToolResult:
    assert isinstance(params, WebSearchParams)
    try:
        data = await exa_search(params.query, params.num_results)   # reuse Project 1's logic
    except Exception as exc:                                        # narrow this later (Project 4)
        return error_result(f"web_search failed: {exc}")
    lines = [f"[{i+1}] {r.title or '(no title)'}\n    {r.url}" for i, r in enumerate(data.results)]
    body = "\n".join(lines) if lines else "No results."
    return ToolResult(content=[TextContent(text=body)], details={"count": len(data.results)})

def web_search_tool() -> AgentTool:
    return AgentTool(
        name="web_search",
        description=(
            "Search the web for current information. Returns a numbered list of "
            "results with titles and URLs. Use this when you need facts you don't "
            "know or that may have changed. To read a result, pass its URL to web_fetch."
        ),
        parameters=WebSearchParams,
        execute=_execute,
    )

